// Helper functions
export function getPuzzlesByTheme(theme: ThemeKey): LichessPuzzle[] {
  return LICHESS_PUZZLES[theme] || [];
}

export function getRandomPuzzleByTheme(theme: ThemeKey): LichessPuzzle | null {
  const puzzles = LICHESS_PUZZLES[theme];
  if (!puzzles || puzzles.length === 0) return null;
  return puzzles[Math.floor(Math.random() * puzzles.length)];
}

export function getRandomPuzzle(): LichessPuzzle {
  const allThemes = Object.keys(LICHESS_PUZZLES) as ThemeKey[];
  const validThemes = allThemes.filter(t => LICHESS_PUZZLES[t].length > 0);
  if (validThemes.length === 0) return LICHESS_PUZZLES['mateIn1'][0]; 
  
  const randomTheme = validThemes[Math.floor(Math.random() * validThemes.length)];
  return getRandomPuzzleByTheme(randomTheme)!;
}

// Flat array of all puzzles for dynamic import compatibility
export const PUZZLES: LichessPuzzle[] = Object.values(LICHESS_PUZZLES).flat();
